// swipe-plan-spec.mjs — the FROZEN, INDEPENDENT specification of the swipe construction
// plan (PLAN-swipe-reveal.md stage 4).
//
// WHAT THIS IS. Declarative DATA — inputs and their expected outcomes — and NOTHING
// ELSE. There is no `if (fromOv) ... else if (incomingBrowse)` in this file, on purpose.
// It is the external oracle in a three-layer scheme:
//
//     swipe-plan-spec.mjs   (this file — the contract, hand-written, reviewed)
//        |
//        +-- rendered by  tools/gen-transition-matrix.mjs  (the human-readable inventory)
//        +-- checked by   test/swipe-transition.test.js     (real js/swipe.js vs this)
//
// WHY NOT GENERATE IT FROM js/swipe.js. A document generated by calling the production
// planner would update in lockstep with a BUG in the planner and the exact-match test
// would still pass — that removes the independent oracle stage 1 was built to be. And a
// single table consumed by BOTH production and the test would only prove production
// reads its own table. So the expected outcomes are written here BY HAND, and changing
// them is a deliberate two-part edit (production + this contract) that a review can see.
//
// SCOPE: CONSTRUCTION ONLY (stage 4). `expectedConstruction` is the { outgoing, incoming,
// renderDestination, decorations } contract js/swipe.js constructionPlanFor() returns.
// The FINALIZATION contract (commit/abort/scroll/stackEffect/reveal) is added as
// `expectedFinalization` when stage 6 builds finalizationPlanFor() — it is intentionally
// absent now, and its absence must NOT be read as "finalization is verified".

// Kind -> a representative screen used to exercise a structural case. Every concrete
// registry pair reduces to one of these by kind; the exhaustive per-pair proof lives in
// the test, which maps each of the 132 pairs onto the matching structural case.
export const REPRESENTATIVE = { home: 'home', browse: 'books', overlay: 'options' };

// The eight structural transitions (home->home is not a transition). Each expectation
// was written against js/app.js start() as it stood at build .226 and mirrors it:
//   outgoing 'app-ghost' iff the SOURCE is not an overlay AND the DESTINATION is browse
//   incoming 'home-snapshot' iff the DESTINATION is home
//   renderDestination 'browse-host' iff the DESTINATION is browse
//   decorations [] for every structural case (the NP pill is a MODIFIER, below)
//
// expectedFinalization carries FROZEN finalization DATA — currently just the abort
// re-render rule ('rerender' iff the source's #browse host was overwritten mid-drag,
// i.e. browse->browse). It is NOT consumed by production in stage 4 (finalizationPlanFor
// lands in stage 6) and NOT compared against production yet; it is here so the rendered
// frozen model keeps documenting abort behaviour without a second mirror. Its presence in
// this fixture must NOT be read as "finalization is verified" — the stage-4 tests compare
// production against expectedConstruction only.
//
// expectedHosts carries the FROZEN sourceHost/destinationHost the STAGE-5 classification must
// project (PLAN-swipe-stage5.md §3, F1-r) — a hand-written independent oracle, NOT derived from
// production. Projection: sourceHost = fromKind==='overlay' ? 'overlay' : 'in-flow'; destinationHost
// = toKind==='overlay' ? 'overlay' : toKind==='browse' ? 'browse-host' : 'home'. It is INERT until
// classifyTransition re-emits the host fields at stage 5 — the generator reads only
// expectedConstruction/expectedFinalization, and the per-pair host proof in swipe-transition.test.js
// is `{ todo }` until then. Its presence here must NOT be read as "the hosts are verified".
export const STRUCTURAL_CASES = [
  { from: 'home',    to: 'browse',  expectedConstruction: { outgoing: 'app-ghost',  incoming: 'real-destination', renderDestination: 'browse-host', decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'in-flow', destinationHost: 'browse-host' } },
  { from: 'home',    to: 'overlay', expectedConstruction: { outgoing: 'real-source', incoming: 'real-destination', renderDestination: 'none',        decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'in-flow', destinationHost: 'overlay' } },
  { from: 'browse',  to: 'home',    expectedConstruction: { outgoing: 'real-source', incoming: 'home-snapshot',    renderDestination: 'none',        decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'in-flow', destinationHost: 'home' } },
  { from: 'browse',  to: 'browse',  expectedConstruction: { outgoing: 'app-ghost',  incoming: 'real-destination', renderDestination: 'browse-host', decorations: [] }, expectedFinalization: { abortRender: 'rerender' }, expectedHosts: { sourceHost: 'in-flow', destinationHost: 'browse-host' } },
  { from: 'browse',  to: 'overlay', expectedConstruction: { outgoing: 'real-source', incoming: 'real-destination', renderDestination: 'none',        decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'in-flow', destinationHost: 'overlay' } },
  { from: 'overlay', to: 'home',    expectedConstruction: { outgoing: 'real-source', incoming: 'home-snapshot',    renderDestination: 'none',        decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'overlay', destinationHost: 'home' } },
  { from: 'overlay', to: 'browse',  expectedConstruction: { outgoing: 'real-source', incoming: 'real-destination', renderDestination: 'browse-host', decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'overlay', destinationHost: 'browse-host' } },
  { from: 'overlay', to: 'overlay', expectedConstruction: { outgoing: 'real-source', incoming: 'real-destination', renderDestination: 'none',        decorations: [] }, expectedFinalization: { abortRender: 'none' },     expectedHosts: { sourceHost: 'overlay', destinationHost: 'overlay' } },
];

// A pane covers the view iff the outgoing is a ghost or the incoming is a Home snapshot.
// Derived from the construction contract, not stored on the plan (no redundant field).
export const paneOf = (c) => c.outgoing === 'app-ghost' || c.incoming === 'home-snapshot';

// The Now Playing pill MODIFIER — the outcome data, written once. NP as SOURCE clones a
// decoration mover based at the outgoing slot (and the body loses np-locked); NP as
// DESTINATION clones one based at the incoming slot. NP cannot be both endpoints (v===v
// is not a transition), so a plan carries at most one. The per-pair test selects
// `source`/`destination` by which endpoint is NP_SCREEN; it does not re-derive the shape.
export const NP_SCREEN = 'nowplaying';
export const NP_DECORATION = {
  source: { kind: 'now-playing-pill', role: 'mover', base: 'outgoing' },
  destination: { kind: 'now-playing-pill', role: 'mover', base: 'incoming' },
};

// DESCRIPTOR SCENARIOS — I16 / §4.3: the plan is proven over DESCRIPTOR scenarios, not
// merely screen-NAME pairs. Two registry entries are PARAMETERIZED (authorBooks carries
// an `author`, files carries a `book`; browse.js:22-23). The screen-name matrix above
// cannot express descriptor identity, so these cover it explicitly.
//
// CONSTRUCTION-LEVEL note (stage 4): descriptor identity changes STACK EFFECTS (navTo
// PUSHES a parameterized descriptor, REPLACES a bare one — app.js:141), which is
// FINALIZATION and lands in stage 6. At the CONSTRUCTION level proven here, every
// well-formed browse descriptor — identical, same-identity, or different-identity —
// yields the same browse->browse construction plan. What stage 4 owes is that each
// descriptor scenario either YIELDS that plan or is REJECTED with a named reason.
//
// SAME-DESTINATION is documented IMPOSSIBLE-BEFORE-THE-PLANNER (the §4.3 option), not
// given a production branch: navTo REPLACES the stack top for a bare same-`v` descriptor
// (app.js:141: `cur.v === desc.v && !desc.author && !desc.book`), so the nav stack can
// never hold two adjacent bare same-`v` entries and the gesture's dest (navStack[-2] /
// fwdStack top / files) is never the bare source. A production throw for it would be an
// UNREACHABLE guard — the dead-code pattern this project forbids (the stage-3 review
// removed such guards). The screen-name matrix documents it by skipping `f.v === t.v`.
// A same-IDENTITY parameterized pair (authorBooks(A)->authorBooks(A)) IS reachable
// (navTo pushes it) and IS a valid transition, so it yields a plan — it is NOT this case.
const BROWSE_PLAN = { outgoing: 'app-ghost', incoming: 'real-destination', renderDestination: 'browse-host', decorations: [] };

// The SEVEN enumerated §15 (Engineering Contract) descriptor-scenario cases. This list is
// the single source; test/descriptor-coverage-gate.test.js fails if the fixture below does
// not tag at least one scenario for each, or tags one that is not in this list (a typo).
export const SEC15_CASES = [
  'same-type-different-identity',
  'same-semantic-separately-allocated',
  'identical-descriptor-object',
  'malformed-parameterized',
  'missing-identity-payload',
  'unknown-screen-type',
  'no-op-same-destination',
];

// The two PARAMETERIZED families (browse.js:22-23 keys them by their payload). The
// parameterized-identity scenarios are GENERATED from this list per Contract §22 (derive
// the inventory, do not hand-repeat it per family) — while the EXPECTED outcome stays the
// hand-written BROWSE_PLAN, so the independent oracle is not generated from production (§16).
const PARAM_FAMILIES = [
  { v: 'authorBooks', payload: 'author' },
  { v: 'files', payload: 'book' },
];
const idOf = (rk) => ({ ratingKey: rk, title: rk });                 // a fresh payload object
const desc = (fam, rk) => ({ v: fam.v, [fam.payload]: idOf(rk) });   // a fresh descriptor

const GENERATED = PARAM_FAMILIES.flatMap((fam) => {
  const shared = desc(fam, 'A');   // ONE object, used at both endpoints → the d -> d case
  return [
    { name: `${fam.v}: same type, different identity (A -> B)`, sec15: 'same-type-different-identity',
      input: { from: desc(fam, 'A'), to: desc(fam, 'B') }, expectedConstruction: BROWSE_PLAN },
    { name: `${fam.v}: same semantic identity, separately allocated (A -> A, distinct objects)`,
      sec15: 'same-semantic-separately-allocated',
      input: { from: desc(fam, 'A'), to: desc(fam, 'A') }, expectedConstruction: BROWSE_PLAN },
    { name: `${fam.v}: identical descriptor object (d -> d, same reference)`, sec15: 'identical-descriptor-object',
      input: { from: shared, to: shared }, expectedConstruction: BROWSE_PLAN },
    // A parameterized name with no payload is BOTH "malformed parameterized" and "missing
    // identity payload" — in this codebase those two §15 cases are one mechanism, so this
    // one scenario legitimately carries both tags (there is no other malformation to model).
    { name: `${fam.v}: malformed / missing required payload is rejected, never planned`,
      sec15: ['malformed-parameterized', 'missing-identity-payload'],
      input: { from: { v: fam.v }, to: { v: 'books' } }, throws: true },
  ];
});

// Every §4.3 / §15 descriptor scenario. Parameterized-identity + malformed cases are
// GENERATED above (one set per family); the remaining §15 cases are explicit below. All
// well-formed browse descriptors yield the same browse->browse CONSTRUCTION plan — the
// differences §4.3 names (referential vs semantic identity, stack effect) are FINALIZATION
// (stage 6); enumerating them now freezes them so stage 6 cannot silently treat referential
// identity where semantic identity is meant.
export const DESCRIPTOR_SCENARIOS = [
  ...GENERATED,
  { name: 'unknown screen type is rejected, never planned', sec15: 'unknown-screen-type',
    input: { from: { v: 'not-a-screen' }, to: { v: 'books' } }, throws: true },
  // No-op / same-destination (a bare same-`v` pair, e.g. books->books) is documented
  // IMPOSSIBLE-BEFORE-THE-PLANNER, not a production branch: navTo REPLACES the stack top for
  // a bare same-`v` descriptor (app.js:141), so the stack never holds adjacent bare same-`v`
  // and the gesture's dest is never the bare source; a production throw would be dead code.
  // This entry is a documented RULING, not a runnable input — the scenario runner skips it.
  { name: 'no-op / same-destination (bare same-v) is impossible-before-the-planner, not a branch',
    sec15: 'no-op-same-destination', documentedImpossible: true },
  // Cross-TYPE (not a §15 category; extra coverage that a parameterized pair need not share v).
  { name: 'cross-type: authorBooks(A) -> files(B) is a browse->browse plan',
    input: { from: desc(PARAM_FAMILIES[0], 'A'), to: desc(PARAM_FAMILIES[1], 'B') },
    expectedConstruction: BROWSE_PLAN },
];

// Named, human-readable modifier cases. The two NP cases are also covered exhaustively
// by the per-pair proof (via NP_DECORATION); kept here as readable examples and for the
// REJECTION contract: a malformed/unknown descriptor must throw, never plan.
export const MODIFIER_CASES = [
  {
    name: 'Now Playing as source (overlay->browse) carries an outgoing-based pill',
    input: { from: { v: 'nowplaying' }, to: { v: 'books' } },
    expectedConstruction: { outgoing: 'real-source', incoming: 'real-destination', renderDestination: 'browse-host',
      decorations: [NP_DECORATION.source] },
  },
  {
    name: 'Now Playing as destination (browse->overlay) carries an incoming-based pill',
    input: { from: { v: 'books' }, to: { v: 'nowplaying' } },
    expectedConstruction: { outgoing: 'real-source', incoming: 'real-destination', renderDestination: 'none',
      decorations: [NP_DECORATION.destination] },
  },
  {
    name: 'an unknown source screen is rejected, never planned',
    input: { from: { v: 'not-a-screen' }, to: { v: 'books' } },
    throws: true,
  },
  {
    name: 'an unknown destination screen is rejected, never planned',
    input: { from: { v: 'books' }, to: { v: 'not-a-screen' } },
    throws: true,
  },
];
